function projectAuditSecretLikePath(path){return/(^|\/)(\.env|\.env\.|.*secret.*|.*token.*|.*password.*|.*passwd.*|.*credential.*|.*private.*|.*\.pem|.*\.key)$/i.test(String(path||""))}
function projectAuditImportant(item,activePath){const p=item.path||"";return p===activePath||p==="cloudflare/wrangler.toml"||p==="package.json"||p==="package-lock.json"||p.endsWith("smoke.yml")||p.includes(".github/workflows")||p.toLowerCase().includes("readme")||p==="cloudflare"||p==="cloudflare/src"}
