async function listRepoDir(c,path=""){const p=clean(path),part=p?`/${pathUrl(p)}`:"";const headers={accept:"application/vnd.github+json","user-agent":"MiniSkynet-v520"};if(c.gh)headers.authorization=`Bearer ${c.gh}`;const r=await fetch(`https://api.github.com/repos/${c.repo}/contents${part}?ref=${encodeURIComponent(c.branch)}`,{headers});const d=await r.json().catch(()=>({}));if(!r.ok)throw new Error(`GitHub listing ${p||"/"} ${r.status}: ${d.message||"request failed"}`);if(!Array.isArray(d))throw new Error(`GitHub listing ${p||"/"} is not a directory`);return d.map(x=>({path:x.path||"",type:x.type||"",size:x.size||0,sha:x.sha||""}))}
