  if(command==="/code_show"){const p=findProp(await arr(env,"proposals"),args);return send(c,chatId,p?.code_draft?`ūüß¨ Code draft ${p.id}\nsummary: ${p.code_draft.summary}\ntarget: ${p.code_draft.target}\ncapability: ${p.code_draft.capability}\nrisk: ${p.risk||p.code_draft.risk}\nexpected: ${p.code_draft.expected}\npatch planner: ${p.patch_plan?p.patch_plan.ok?"PASS":"BLOCKED":"none"}\n\n${clip(p.code_draft.new_content,2600)}`:"Code draft –Ĺ–Ķ—ā.")}
