async function telegram(request,env){const c=await cfg(env),msg=parse(await request.json().catch(()=>null));if(!msg)return out({ok:true});if(!ownerOk(c,msg.userId)){await send(c,msg.chatId,"‚õĒ –Ē–ĺ—Ā—ā—É–Ņ –∑–į–ļ—Ä—č—ā.");return out({ok:true,denied:true})}try{if(msg.command&&!CMDS.has(msg.command)){await send(c,msg.chatId,`–Ě–Ķ –∑–Ĺ–į—é –ļ–ĺ–ľ–į–Ĺ–ī—É ${msg.command}. /help ‚ÄĒ —Ā–Ņ–ł—Ā–ĺ–ļ. –ú–ĺ–ī–Ķ–Ľ—Ć –Ĺ–Ķ –≤—č–∑—č–≤–į—é.`);return out({ok:true,unknown_command:true,version:VERSION})}await handle(env,c,msg);return out({ok:true,command:msg.command||"text",version:VERSION})}catch(e){await send(c,msg.chatId,`‚ĚĆ Core error: ${clip(e.message||e,1000)}`);return out({ok:false,error:String(e.message||e),version:VERSION},500)}}
export default{async fetch(request,env){const url=new URL(request.url);if(url.pathname==="/"||url.pathname==="/health")return out(health());if(url.pathname==="/telegram"&&request.method==="POST")return telegram(request,env);return out({ok:false,error:"not found",version:VERSION},404)},async scheduled(event,env,ctx){try{await scheduledAliveV1(event,env)}catch(e){console.log("scheduledAliveV1 error",String(e?.message||e))}}};
